const grouped = {}

for (const item of items) {
  const cust = item.json.customer_name
  if (!grouped[cust]) {
    grouped[cust] = {
      customer_name: cust,
      prediction_rows: []
    }
  }
  grouped[cust].prediction_rows.push(item.json)
}

return Object.values(grouped).map(i => ({ json: i }))

const items = $input.all();
const rows = items.map(item => item.json);

const numPeriods = 1;

return [{
  json: {
    data: rows,
    num_periods: numPeriods
  }
}];

const products = new Set()

for (const item of items) {
  if (item.json.product_spec) {
    products.add(item.json.product_spec)
  }
}

return [
  {
    json: {
      candidate_products: [...products]
    }
  }
]

const READONLY_FIELDS = [
  'upload_id',
  'prediction_month', 'prediction_year', 'prediction_period_label',
  'suggested_amount_sales', 'suggested_freight_cost',
  'suggested_cogs', 'predicted_net_sales', 'needs_manager_review',
  'reason'
  // original_row_id stays — AI needs it to reference rows
];

let allCandidates = [];
const customerMap = {};

for (const item of items) {
  if (item.json.candidate_products?.length) {
    allCandidates = item.json.candidate_products;
  }
  if (item.json.prediction_rows) {
    const key = item.json.customer_name;
    customerMap[key] = item.json;
  }
}

const results = [];
for (const [customerName, data] of Object.entries(customerMap)) {
  const rows = data.prediction_rows;
  const activeFamilies = new Set(rows.map(r => r.product_spec.split(' ')[0]));

  const filteredCandidates = allCandidates.filter(p =>
    activeFamilies.has(p.split(' ')[0])
  );

  const slimRows = rows.map(r => {
    const slim = { ...r };
    for (const f of READONLY_FIELDS) delete slim[f];
    return slim;
  });

  results.push({
    json: {
      customer_name: customerName,
      prediction_rows: slimRows,
      full_rows: rows,
      candidate_products: filteredCandidates
    }
  });
}
return results;

function generateUUID() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

const originalItems = $('Code in JavaScript1').all();
const currentIndex = $itemIndex;
const fullRows = $('Loop Over Items').item?.json?.full_rows ?? [];

function parseAgentOutput(raw) {
  if (!raw || typeof raw !== 'string') return null;
  let cleaned = raw.replace(/```json\s*/gi, '').replace(/```\s*/gi, '').trim();
  try {
    const parsed = JSON.parse(cleaned);
    return Array.isArray(parsed) ? parsed : null;
  } catch(e) {}
  try {
    const lastGoodBracket = cleaned.lastIndexOf('},');
    if (lastGoodBracket !== -1) {
      const salvaged = cleaned.substring(0, lastGoodBracket + 1) + ']';
      const parsed = JSON.parse(salvaged);
      return Array.isArray(parsed) ? parsed : null;
    }
  } catch(e) {}
  return null;
}

function normalizeAction(action) {
  if (!action) return 'MAINTAIN';
  const map = {
    'SUBTITUDE': 'SUBSTITUTE',
    'SUBSTITUTE': 'SUBSTITUTE',
    'REPLACE': 'SUBSTITUTE',
    'BOOST': 'BOOST',
    'REDUCE': 'REDUCE',
    'MAINTAIN': 'MAINTAIN',
    'INVESTIGATE': 'INVESTIGATE'
  };
  return map[action.toUpperCase()] ?? 'MAINTAIN';
}

const raw = items[0].json.output;
const aiDiff = parseAgentOutput(raw);

// If AI failed or returned empty — return all full rows untouched
if (!aiDiff || aiDiff.length === 0) {
  return fullRows.map(row => ({ json: row }));
}

// Build a map of AI changes keyed by original_row_id
const diffMap = {};
for (const diff of aiDiff) {
  if (diff.original_row_id) {
    diffMap[diff.original_row_id] = diff;
  }
}

// Merge AI diff onto each full row
const result = fullRows.map(row => {
  const diff = diffMap[row.original_row_id];

  if (!diff) {
    // No change from AI — return row exactly as-is
    return { json: row };
  }

  // Apply only the fields AI returned
  const merged = { ...row };
  const aiFields = ['action', 'confidence_score', 'reason', 'suggested_quantity', 'product_spec', 'replaced_from'];
  for (const f of aiFields) {
    if (diff[f] !== undefined) merged[f] = diff[f];
  }
  merged.action = normalizeAction(merged.action);

  return { json: merged };
});

return result;

